input.old_string:
# Extract first user message from JSONL transcript
# Format: {"type": "user", "message": {"role": "user", "content": "..."}}
local first_message=$(head -20 "$transcript_path" | jq -r 'select(.type == "user") | .message.content // empty' 2>/dev/null | head -1 | tr -d '\n' | sed 's/^[[:space:]]*//;s/[[:space:]]*$//')

input.new_string:
# Extract first user message from JSONL transcript (skip "Warmup")
# Format: {"type": "user", "message": {"role": "user", "content": "..."}}
local first_message=$(jq -r 'select(.type == "user") | .message.content // empty' "$transcript_path" 2>/dev/null | grep -iv "^warmup$" | head -1 | tr -d '\n' | sed 's/^[[:space:]]*//;s/[[:space:]]*$//')

